(()=>{if(window.pdfjsLib)return;const s=document.createElement('script');s.src='https://cdn.jsdelivr.net/npm/pdfjs-dist/build/pdf.min.js';s.onload=()=>{if(window.pdfjsLib)pdfjsLib.GlobalWorkerOptions.workerSrc='https://cdn.jsdelivr.net/npm/pdfjs-dist/build/pdf.worker.min.js';};document.head.appendChild(s);})();
